package ssg
package js
package compress

import CompressTestHelper.{ AllOff, assertCompresses }

final class CompressRegexpSuite extends munit.FunSuite {

  override val munitTimeout = scala.concurrent.duration.Duration(120, "s")

  // =========================================================================
  // regexp_1
  // =========================================================================
  test("regexp_1") {
    assertCompresses(
      input = "console.log(JSON.stringify(\"COMPASS? Overpass.\".match(/([Sap]+)/ig)))",
      expected = "console.log(JSON.stringify(\"COMPASS? Overpass.\".match(/([Sap]+)/gi)))",
      options = AllOff
    )
  }

  // =========================================================================
  // regexp_2
  // =========================================================================
  test("regexp_2") {
    assertCompresses(
      input = "console.log(JSON.stringify(\"COMPASS? Overpass.\".match(new RegExp(\"(pass)\", \"ig\"))))",
      expected = "console.log(JSON.stringify(\"COMPASS? Overpass.\".match(/(pass)/gi)))",
      options = AllOff.copy(
        evaluate = true,
        unsafe = true
      )
    )
  }

  // =========================================================================
  // unsafe_slashes
  // =========================================================================
  test("unsafe_slashes".fail) {
    assertCompresses(
      input = "console.log(new RegExp(\"^https//\"))",
      expected = "console.log(/^https\\/\\//)",
      options = AllOff.copy(
        unsafe = true
      )
    )
  }

  // =========================================================================
  // unsafe_nul_byte
  // =========================================================================
  test("unsafe_nul_byte".fail) {
    assertCompresses(
      input = "console.log(new RegExp(\"\\0\"))",
      expected = "console.log(/\\0/)",
      options = AllOff.copy(
        unsafe = true
      )
    )
  }

  // =========================================================================
  // double_escape
  // =========================================================================
  test("double_escape".fail) {
    assertCompresses(
      input = "/\\🏳0\\🌈️\\☺/",
      expected = "/\\ud83c\\udff30\\ud83c\\udf08\\ufe0f\\u263a/",
      options = AllOff
    )
  }

  // =========================================================================
  // regexp_no_ddos
  // =========================================================================
  test("regexp_no_ddos") {
    assertCompresses(
      input = """console.log(/(b+)b+/.test("bbb"))
        console.log(RegExp("(b+)b+").test("bbb"))""".stripMargin.trim,
      expected = """console.log(/(b+)b+/.test("bbb"))
        console.log(RegExp("(b+)b+").test("bbb"))""".stripMargin.trim,
      options = AllOff.copy(
        evaluate = true,
        unsafe = true
      )
    )
  }

}
